    if not isinstance(desc, str):
        return None
    # Look for pattern: "in City, State," or similar
    match = re.search(r'in\s+[^,]+,\s*([A-Z]{2})\b', desc)
    if match:
        return match.group(1)
    # Alternative: just look for 2-letter state code anywhere
    match2 = re.search(r'\b([A-Z]{2})\b', desc)
    if match2:
        return match2.group(1)
    return None

df_businesses['state'] = df_businesses['description'].apply(extract_state_v2)

print('\nState extraction results:')
print(df_businesses['state'].value_counts().head(10))

# Convert rating
df_reviews['rating'] = pd.to_numeric(df_reviews['rating'], errors='coerce')

# Merge
merged = df_reviews.merge(
    df_businesses[['id_num', 'state']],
    on='id_num',
    how='left'
)

print(f'\nMerged data: {len(merged)} rows')
print('States in merged data:', merged['state'].value_counts().head())

# Calculate state stats
if not merged.empty:
    state_stats = merged.groupby('state').agg({
        'rating': ['count', 'mean']
    }).round(2)
    state_stats.columns = ['review_count', 'avg_rating']
    state_stats = state_stats.sort_values('review_count', ascending=False)

    if not state_stats.empty:
        top_state = state_stats.iloc[0]
        result = {
            'state': str(state_stats.index[0]),
            'review_count': int(top_state['review_count']),
            'avg_rating': float(top_state['avg_rating'])
        }
    else:
        result = {'error': 'No state statistics could be calculated'}
else:
    result = {'error': 'No data after merge'}

print('\n__RESULT__:')
print(json.dumps(result))"}

